INSERT INTO `receitas` VALUES (1,'Vitamina de Banana','Bebida','Vitamina cremosa e nutritiva perfeita para o cafe da manha.','Bata no liquidificador 2 bananas maduras com 300ml de leite e 1 colher de mel. Adicione gelo e sirva gelado.','Facil',5,NULL,'[\"Lactose\"]','bebida',NULL),(2,'Salada de Frutas','Sobremesa','Salada refrescante com frutas da estacao.','Corte em cubos: 1 maca, 1 banana, 1 laranja e 1 manga. Misture tudo numa tigela e regue com suco de laranja. Sirva gelada.','Facil',10,NULL,'[]','fruta','Vegano'),(3,'Ovos Mexidos','Cafe da Manha','Ovos mexidos cremosos e simples para o dia a dia.','Bata 3 ovos com sal e pimenta. Derreta manteiga numa frigideira e adicione os ovos. Mexa em fogo baixo ate cremoso. Sirva com torrada.','Facil',10,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(4,'Torrada com Abacate','Cafe da Manha','Torrada crocante com pasta de abacate temperada.','Amasse 1 abacate maduro com sal, limao e pimenta. Espalhe sobre torradas e finalize com azeite e pimenta calabresa.','Facil',10,NULL,'[\"Gluten\"]','outro','Vegetariano'),(5,'Suco de Laranja com Cenoura','Bebida','Suco detox rico em vitaminas.','Bata no liquidificador 3 laranjas espremidas com 1 cenoura ralada e um pouco de gengibre. Coe e sirva gelado.','Facil',5,NULL,'[]','bebida','Vegano'),(6,'Iogurte com Granola','Cafe da Manha','Cafe da manha rapido e nutritivo.','Coloque iogurte natural numa tigela. Adicione granola por cima e finalize com mel e frutas vermelhas.','Facil',5,NULL,'[\"Lactose\", \"Gluten\"]','laticinio','Vegetariano'),(7,'Omelete de Queijo','Almoco','Omelete simples e delicioso para qualquer hora.','Bata 3 ovos com sal e pimenta. Despeje numa frigideira untada. Quando firmar, adicione queijo ralado, dobre ao meio e sirva.','Facil',10,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(8,'Arroz Branco','Acompanhamento','Arroz soltinho e perfeito para acompanhar qualquer prato.','Refogue alho picado no azeite. Adicione 2 xicaras de arroz lavado e frite por 2 minutos. Adicione 4 xicaras de agua quente e sal. Cozinhe em fogo baixo por 15 minutos.','Facil',25,NULL,'[]','grao','Vegano'),(9,'Feijao Simples','Acompanhamento','Feijao temperado tradicional brasileiro.','Refogue cebola e alho. Adicione feijao cozido com o caldo. Tempere com sal, louro e pimenta. Cozinhe por 10 minutos e ajuste o tempero.','Facil',20,NULL,'[]','grao','Vegano'),(10,'Banana Assada com Canela','Sobremesa','Sobremesa rapida e deliciosa.','Coloque bananas cortadas ao meio numa assadeira. Polvilhe com canela e acucar mascavo. Asse em forno a 180C por 15 minutos.','Facil',20,NULL,'[]','fruta','Vegano'),(11,'Macarrao ao Alho e Oleo','Almoco','Macarrao simples e saboroso pronto em minutos.','Cozinhe o macarrao al dente. Frite farto alho picado em azeite ate dourar. Misture ao macarrao escorrido, adicione salsinha e queijo parmesao.','Facil',20,NULL,'[\"Gluten\", \"Lactose\"]','grao','Vegetariano'),(12,'Salpicao de Frango','Almoco','Salpicao cremoso e colorido.','Desfie frango cozido. Misture com cenoura ralada, milho, ervilha e maionese. Tempere com sal e pimenta. Sirva gelado.','Facil',20,NULL,'[\"Ovo\"]','carne',NULL),(13,'Pure de Batata','Acompanhamento','Pure cremoso e irresistivel.','Cozinhe batatas descascadas ate amolecer. Amasse com manteiga, leite quente e sal ate ficar cremoso. Finalize com noz-moscada.','Facil',30,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(14,'Sopa de Legumes','Jantar','Sopa nutritiva e reconfortante.','Refogue cebola e alho. Adicione cenoura, batata e chuchu em cubos. Cubra com agua e cozinhe ate os legumes amolecerem. Tempere com sal e cheiro-verde.','Facil',35,NULL,'[]','verdura','Vegano'),(15,'Frango Grelhado','Almoco','Frango grelhado simples e saudavel.','Tempere files de frango com sal, limao, alho e pimenta. Deixe marinar 30 minutos. Grelhe numa frigideira quente por 5 minutos de cada lado.','Facil',40,NULL,'[]','carne',NULL),(16,'Risoto de Queijo','Almoco','Risoto cremoso e sofisticado.','Refogue cebola em manteiga. Adicione arroz arboreo e frite. Adicione vinho branco e mexa. Acrescente caldo quente aos poucos mexendo sempre. Finalize com queijo parmesao e manteiga.','Media',40,NULL,'[\"Lactose\"]','grao','Vegetariano'),(17,'Frango ao Molho de Tomate','Almoco','Frango suculento com molho caseiro de tomate.','Tempere e sele o frango. Reserve. Refogue cebola e alho, adicione tomates picados e deixe cozinhar. Volte o frango ao molho e cozinhe por 20 minutos. Finalize com manjericao.','Media',45,NULL,'[]','carne',NULL),(18,'Quiche de Legumes','Almoco','Quiche cremosa com legumes variados.','Forre uma forma com massa podre. Refogue brocolis, cenoura e cebola. Bata ovos com creme de leite e queijo. Misture os legumes e despeje na forma. Asse a 180C por 35 minutos.','Media',60,NULL,'[\"Gluten\", \"Lactose\", \"Ovo\"]','ovo','Vegetariano'),(19,'Carne Moida com Batata','Almoco','Prato completo e reconfortante.','Doure cebola e alho. Adicione carne moida e frite ate secar. Junte batata em cubos, tomate picado e temperos. Adicione agua e cozinhe ate a batata amolecer.','Media',40,NULL,'[]','carne',NULL),(20,'Peixe Assado com Ervas','Jantar','Peixe temperado com ervas frescas e assado no forno.','Tempere o peixe com azeite, alho, limao, tomilho e alecrim. Deixe marinar 30 minutos. Asse a 200C por 25 minutos. Sirva com legumes assados.','Media',60,NULL,'[]','carne',NULL),(21,'Torta de Legumes','Almoco','Torta salgada recheada com legumes coloridos.','Prepare a massa com farinha, ovo, manteiga e sal. Forre a forma. Refogue os legumes e misture com ovos batidos e queijo. Despeje na forma e asse a 180C por 40 minutos.','Media',70,NULL,'[\"Gluten\", \"Lactose\", \"Ovo\"]','verdura','Vegetariano'),(22,'Strogonoff de Frango','Almoco','Strogonoff cremoso e saboroso.','Tempere e sele o frango em cubos. Refogue cebola e alho. Adicione extrato de tomate, mostarda e creme de leite. Volte o frango e cozinhe por 15 minutos. Sirva com arroz e batata palha.','Media',40,NULL,'[\"Lactose\"]','carne',NULL),(23,'Lasanha de Carne','Jantar','Lasanha tradicional com molho bolonhesa e bechamel.','Prepare o bolonhesa com carne moida e tomate. Prepare o bechamel com manteiga, farinha e leite. Monte camadas de massa, bolonhesa, bechamel e queijo. Asse coberto por 30 minutos e descoberto por 15.','Media',90,NULL,'[\"Gluten\", \"Lactose\"]','carne',NULL),(24,'Curry de Grao-de-Bico','Almoco','Curry aromatico e vegetariano.','Refogue cebola, alho e gengibre. Adicione curry em po, curcuma e cominho. Junte tomate picado e grao-de-bico cozido. Adicione leite de coco e cozinhe por 20 minutos. Sirva com arroz.','Media',35,NULL,'[]','grao','Vegano'),(25,'Frango Xadrez','Almoco','Prato oriental colorido e saboroso.','Corte frango em cubos e marine com shoyu, gengibre e alho. Wok quente com oleo, frite o frango. Adicione pimentao vermelho, verde e amarelo, cebola e castanha de caju. Finalize com molho de ostra.','Media',35,NULL,'[]','carne',NULL),(26,'Caldo Verde','Jantar','Sopa portuguesa reconfortante.','Cozinhe batatas com cebola e alho. Bata tudo no liquidificador. Volte ao fogo e adicione couve fatiada fina e linguica em rodelas. Tempere e sirva quente com azeite.','Media',40,NULL,'[]','verdura','Vegano'),(27,'Bolo de Cenoura','Sobremesa','Bolo fofo de cenoura com cobertura de chocolate.','Bata no liquidificador cenoura, ovos, oleo e acucar. Misture com farinha e fermento. Asse a 180C por 35 minutos. Cubra com calda de chocolate quente.','Media',50,NULL,'[\"Gluten\", \"Ovo\"]','fruta','Vegetariano'),(28,'Pao de Forma Caseiro','Cafe da Manha','Pao macio e delicioso feito em casa.','Misture farinha, fermento, sal, acucar, ovo e leite morno. Sove por 10 minutos. Deixe crescer 1 hora. Modele, coloque na forma e deixe crescer mais 30 minutos. Asse a 180C por 30 minutos.','Media',120,NULL,'[\"Gluten\", \"Lactose\", \"Ovo\"]','outro','Vegetariano'),(29,'Moqueca de Peixe','Almoco','Moqueca baiana aromatica e saborosa.','Marine o peixe com limao, sal e alho. Refogue cebola, pimentao e tomate. Adicione leite de coco e azeite de dende. Coloque o peixe e cozinhe por 15 minutos. Finalize com coentro.','Media',45,NULL,'[]','carne',NULL),(30,'Hamburguer Artesanal','Almoco','Hamburguer suculento feito em casa.','Misture carne moida com cebola ralada, alho, sal e pimenta. Forme os hamburgueres. Grelhe por 4 minutos de cada lado. Monte no pao com alface, tomate, queijo e molho de sua preferencia.','Media',30,NULL,'[\"Gluten\", \"Lactose\"]','carne',NULL),(31,'Sushi Caseiro','Jantar','Sushi fresco feito em casa.','Prepare o arroz para sushi com vinagre, acucar e sal. Espalhe sobre alga nori. Adicione peixe fresco e pepino em tiras. Enrole firmemente com a esteira de bambu. Corte em fatias e sirva com shoyu e wasabi.','Dificil',90,NULL,'[]','carne',NULL),(32,'Croissant Folhado','Cafe da Manha','Croissant amanteigado e folhado.','Prepare a massa com farinha, leite, fermento e acucar. Incorpore manteiga gelada em camadas dobrando repetidamente. Refrigere entre as dobras. Modele, deixe crescer e asse a 200C por 20 minutos ate dourar.','Dificil',240,NULL,'[\"Gluten\", \"Lactose\"]','outro','Vegetariano'),(33,'Macarons Franceses','Sobremesa','Biscoitos franceses delicados e coloridos.','Bata claras em neve com acucar. Incorpore farinha de amendoas e acucar de confeiteiro. Pipe sobre papel manteiga e deixe secar 30 minutos. Asse a 150C por 12 minutos. Recheie com ganache ou buttercream.','Dificil',120,NULL,'[\"Ovo\", \"Lactose\"]','ovo',NULL),(34,'Beef Wellington','Jantar','File mignon envolvido em massa folhada.','Sele o file e cubra com mostarda. Envolva com duxelles de cogumelos e presunto. Cubra com massa folhada e asse a 220C por 25 minutos. Deixe descansar antes de cortar.','Dificil',120,NULL,'[\"Gluten\"]','carne',NULL),(35,'Cheesecake New York','Sobremesa','Cheesecake cremoso estilo Nova Iorque.','Misture biscoito triturado com manteiga e forre a forma. Bata cream cheese com acucar, ovos e baunilha. Despeje sobre a base e asse em banho-maria a 160C por 60 minutos. Refrigere por 4 horas.','Dificil',90,NULL,'[\"Gluten\", \"Lactose\", \"Ovo\"]','outro','Vegetariano'),(36,'Ramen Caseiro','Jantar','Ramen japones com caldo rico e ingredientes frescos.','Cozinhe ossos de porco por 4 horas para o caldo. Prepare o tare com shoyu, mirin e sake. Cozinhe o macarrao. Monte a tigela com caldo quente, tare, macarrao, ovo cozido, nori, cebolinha e bambu.','Dificil',300,NULL,'[\"Gluten\", \"Ovo\"]','carne',NULL),(37,'Souffle de Queijo','Jantar','Souffle leve e aerado que impressiona.','Prepare bechamel e adicione queijo gruyere. Incorpore gemas. Bata claras em neve firme e incorpore delicadamente. Despeje em ramequins untados e asse a 200C por 12 minutos sem abrir o forno.','Dificil',45,NULL,'[\"Lactose\", \"Ovo\"]','laticinio','Vegetariano'),(38,'Pato a Laranja','Jantar','Prato classico da culinaria francesa.','Tempere o pato e asse a 180C por 2 horas regando com a propria gordura. Prepare o molho com suco de laranja, vinho branco, caldo de carne e Grand Marnier. Reduza ate engrossar e sirva sobre o pato.','Dificil',150,NULL,'[]','carne',NULL),(39,'Tiramisu','Sobremesa','Sobremesa italiana classica com cafe e mascarpone.','Bata gemas com acucar. Incorpore mascarpone. Bata claras em neve e misture delicadamente. Mergulhe biscoitos champagne em cafe forte. Monte camadas alternando creme e biscoito. Finalize com cacau em po e refrigere 4 horas.','Dificil',60,NULL,'[\"Lactose\", \"Ovo\", \"Gluten\"]','outro','Vegetariano'),(40,'Boeuf Bourguignon','Jantar','Ensopado frances de carne ao vinho tinto.','Sele cubos de carne bovina em bacon. Reserve. Refogue cenoura, cebola e alho. Adicione vinho tinto, caldo de carne e bouquet garni. Volte a carne e cozinhe por 2 horas em fogo baixo. Adicione cogumelos e cebolinha no final.','Dificil',180,NULL,'[]','carne',NULL),(41,'Creme Brulee','Sobremesa','Sobremesa francesa com crosta de acucar caramelizado.','Aqueca creme de leite com baunilha. Bata gemas com acucar e incorpore o creme quente aos poucos. Despeje em ramequins e asse em banho-maria a 160C por 40 minutos. Refrigere e caramelize o acucar com macarico antes de servir.','Dificil',70,NULL,'[\"Lactose\", \"Ovo\"]','outro','Vegetariano'),(50,'Brigadeiro Caseiro','Sobremesa','O doce mais amado do Brasil feito do jeito tradicional.','Misture 1 lata de leite condensado com 3 colheres de cacau em po e 1 colher de manteiga numa panela. Cozinhe em fogo medio mexendo sempre ate soltar do fundo. Deixe esfriar, enrole em bolinhas e passe no granulado.','Facil',20,NULL,'[\"Lactose\"]','outro','Vegetariano'),(51,'Frango com Requeijao','Almoco','Frango cremoso e irresistivel que agrada a todos.','Tempere filés de frango com sal, alho e pimenta. Grelhe numa frigideira ate dourar dos dois lados. Coloque numa assadeira, cubra com requeijao cremoso e queijo parmesao ralado. Leve ao forno a 200C por 15 minutos ate gratinar.','Facil',35,NULL,'[\"Lactose\"]','carne',NULL),(52,'Bolinho de Arroz','Almoco','Otima pedida para aproveitar o arroz que sobrou.','Misture 2 xicaras de arroz cozido com 1 ovo, 2 colheres de farinha de trigo, queijo ralado, sal e salsinha picada. Forme bolinhos com as maos. Frite em oleo quente ate dourar dos dois lados. Escorra no papel toalha e sirva quente.','Facil',25,NULL,'[\"Gluten\", \"Ovo\", \"Lactose\"]','grao','Vegano'),(97,'Mingau de Aveia','Cafe da Manha','Mingau cremoso e reconfortante para o cafe da manha.','Ferva 300ml de leite. Adicione 4 colheres de aveia e mexa em fogo baixo por 5 minutos. Adoce com mel e finalize com canela em po.','Facil',10,NULL,'[\"Lactose\"]','grao','Vegetariano'),(98,'Pudim de Leite','Sobremesa','O classico pudim brasileiro com calda de caramelo.','Faca o caramelo derretendo acucar na forma. Bata no liquidificador 1 lata de leite condensado, 1 lata de leite e 3 ovos. Despeje na forma e asse em banho-maria a 180C por 50 minutos. Desenforme frio.','Media',70,NULL,'[\"Lactose\", \"Ovo\"]','outro','Vegetariano'),(99,'Panqueca de Leite','Cafe da Manha','Panqueca classica para usar o leite proximo da validade.','Bata no liquidificador 2 xicaras de leite, 2 ovos, 1 xicara de farinha e 1 pitada de sal. Frite em frigideira untada por 2 minutos de cada lado. Sirva com mel ou recheio de sua preferencia.','Facil',20,NULL,'[\"Lactose\", \"Ovo\", \"Gluten\"]','grao','Vegetariano'),(100,'Molho Branco Caseiro','Acompanhamento','Molho bechamel cremoso para massas e gratinados.','Derreta 2 colheres de manteiga. Adicione 2 colheres de farinha e mexa por 1 minuto. Acrescente 500ml de leite aos poucos mexendo sempre. Tempere com sal, pimenta e noz-moscada. Cozinhe ate engrossar.','Facil',15,NULL,'[\"Lactose\", \"Gluten\"]','laticinio','Vegetariano'),(101,'Vitamina de Mamao','Bebida','Vitamina leve e digestiva perfeita para o cafe da manha.','Bata no liquidificador 1 fatia de mamao com 300ml de leite e 1 colher de mel. Adicione gelo e sirva gelado.','Facil',5,NULL,'[\"Lactose\"]','bebida',NULL),(102,'Ovo Cozido Temperado','Cafe da Manha','Ovo cozido com temperos especiais para um lanche nutritivo.','Cozinhe ovos em agua fervente por 10 minutos. Descasque e corte ao meio. Tempere com azeite, sal, pimenta e paprica. Finalize com cebolinha picada.','Facil',12,NULL,'[\"Ovo\"]','ovo','Vegetariano'),(103,'Fritada de Legumes','Almoco','Fritada colorida com legumes da geladeira.','Bata 4 ovos com sal e pimenta. Refogue cebola, pimentao e tomate picados. Despeje os ovos sobre os legumes e cozinhe em fogo baixo tampado por 8 minutos. Finalize no forno por 5 minutos.','Facil',20,NULL,'[\"Ovo\"]','ovo','Vegetariano'),(104,'Ovo Pochê','Cafe da Manha','Ovo pochê elegante e facil de fazer.','Ferva agua com um fio de vinagre. Crie um redemoinho com a colher e quebre o ovo no centro. Cozinhe por 3 minutos. Retire com escumadeira e sirva sobre torrada com sal e pimenta.','Media',10,NULL,'[\"Ovo\", \"Gluten\"]','ovo','Vegetariano'),(105,'Maionese Caseira','Acompanhamento','Maionese cremosa feita em casa com poucos ingredientes.','Bata 1 ovo inteiro no liquidificador com sal e mostarda. Com o liquidificador ligado, adicione 200ml de oleo em fio fino ate emulsionar. Finalize com limao e ajuste o sal.','Facil',10,NULL,'[\"Ovo\"]','ovo','Vegetariano'),(106,'Caldo de Frango','Jantar','Caldo nutritivo e reconfortante para dias frios.','Cozinhe frango com cebola, alho, cenoura e salsao por 40 minutos. Retire o frango e desfie. Coe o caldo, volte ao fogo com o frango desfiado, batata em cubos e tempere com sal e cheiro-verde.','Facil',50,NULL,'[]','carne',NULL),(107,'Frango a Parmegiana','Almoco','Classico frango a parmegiana com molho de tomate e queijo.','Empane filés de frango em farinha, ovo e farinha de rosca. Frite ate dourar. Cubra com molho de tomate e queijo mussarela. Asse a 200C por 15 minutos ate o queijo derreter.','Media',40,NULL,'[\"Gluten\", \"Ovo\", \"Lactose\"]','carne',NULL),(108,'Frango Desfiado Refogado','Almoco','Frango desfiado temperado para recheios e acompanhamentos.','Cozinhe o frango na pressao por 20 minutos. Desfie. Refogue cebola e alho, adicione o frango desfiado, tomate picado e temperos. Cozinhe por 10 minutos e finalize com cheiro-verde.','Facil',35,NULL,'[]','carne',NULL),(109,'Picadinho de Carne','Almoco','Picadinho suculento com legumes e molho encorpado.','Corte a carne em cubos e tempere. Sele em fogo alto. Reserve. Refogue cebola, alho e tomate. Volte a carne, adicione agua e cozinhe por 30 minutos. Finalize com azeitona e cheiro-verde.','Media',45,NULL,'[]','carne',NULL),(110,'Almondega ao Molho','Almoco','Almôndegas suculentas em molho de tomate caseiro.','Misture carne moida com ovo, farinha de rosca, alho, sal e pimenta. Forme bolinhas. Frite ou asse. Prepare molho de tomate e cozinhe as almôndegas no molho por 15 minutos.','Media',45,NULL,'[\"Gluten\", \"Ovo\"]','carne',NULL),(111,'Batata Assada','Acompanhamento','Batata assada crocante por fora e macia por dentro.','Lave as batatas e corte em gomos. Tempere com azeite, sal, alho e ervas. Espalhe numa assadeira e asse a 220C por 35 minutos virando na metade do tempo.','Facil',40,NULL,'[]','verdura','Vegano'),(112,'Sopa Creme de Batata','Jantar','Sopa cremosa e reconfortante de batata.','Cozinhe batatas com cebola e alho em agua com sal. Bata tudo no liquidificador com creme de leite ate ficar cremoso. Volte ao fogo, ajuste o sal e finalize com azeite e cebolinha.','Facil',30,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(113,'Peixe na Frigideira','Almoco','Filé de peixe grelhado com ervas e limao.','Tempere o filé com sal, limao, alho e ervas. Aqueça azeite numa frigideira. Grelhe o peixe por 4 minutos de cada lado ate dourar. Sirva com arroz e salada.','Facil',15,NULL,'[]','carne',NULL),(114,'Escabeche de Peixe','Almoco','Peixe marinado em molho agridoce de legumes.','Frite postas de peixe empanadas. Reserve. Refogue cebola, cenoura e pimentao em rodelas. Adicione vinagre, acucar, sal e louro. Despeje sobre o peixe e deixe marinar 30 minutos antes de servir.','Media',45,NULL,'[\"Gluten\"]','carne',NULL),(115,'Queijo Grelhado','Cafe da Manha','Queijo grelhado crocante por fora e derretido por dentro.','Corte fatias grossas de queijo. Grelhe numa frigideira antiaderente seca em fogo medio por 2 minutos de cada lado ate formar crosta dourada. Sirva quente com geleia ou mel.','Facil',8,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(116,'Sanduiche Quente de Queijo','Cafe da Manha','Sanduiche tostado com queijo derretido.','Passe manteiga nas fatias de pao. Recheie com queijo fatiado. Toste numa frigideira tampada em fogo baixo por 3 minutos de cada lado ate o queijo derreter e o pao dourar.','Facil',8,NULL,'[\"Lactose\", \"Gluten\"]','laticinio','Vegetariano'),(117,'Arroz de Forno','Almoco','Arroz cremoso gratinado no forno.','Misture arroz cozido com creme de leite, queijo ralado, milho e ervilha. Coloque numa assadeira, cubra com mais queijo e asse a 200C por 20 minutos ate gratinar.','Facil',30,NULL,'[\"Lactose\"]','grao','Vegetariano'),(118,'Sopa de Arroz','Jantar','Sopa reconfortante com arroz e legumes.','Refogue cebola e alho. Adicione cenoura e batata em cubos. Cubra com agua ou caldo e cozinhe 15 minutos. Adicione arroz e cozinhe mais 15 minutos. Tempere e finalize com cheiro-verde.','Facil',35,NULL,'[]','grao','Vegano'),(119,'Macarrao a Bolonhesa','Almoco','Macarrao com molho de carne moida tradicional.','Refogue cebola, alho e cenoura. Adicione carne moida e frite. Junte tomate pelado e temperos. Cozinhe 30 minutos. Misture ao macarrao cozido al dente e sirva com parmesao.','Media',45,NULL,'[\"Gluten\", \"Lactose\"]','grao',NULL),(120,'Macarrao de Forno','Almoco','Macarrao gratinado cremoso e irresistivel.','Cozinhe o macarrao al dente. Misture com molho branco, presunto e queijo. Coloque numa assadeira, cubra com mais queijo e asse a 200C por 25 minutos ate gratinar.','Media',50,NULL,'[\"Gluten\", \"Lactose\"]','grao','Vegetariano'),(121,'Cenoura Refogada','Acompanhamento','Cenoura refogada com manteiga e ervas.','Corte cenouras em rodelas. Refogue em manteiga com alho por 10 minutos ate amolecer. Tempere com sal, pimenta e salsinha picada. Sirva como acompanhamento.','Facil',15,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(122,'Suco de Cenoura com Laranja','Bebida','Suco nutritivo e energizante.','Bata no liquidificador 2 cenouras raladas com o suco de 3 laranjas e um pedaco de gengibre. Coe e sirva gelado com gelo.','Facil',5,NULL,'[]','bebida','Vegano'),(123,'Molho de Tomate Caseiro','Acompanhamento','Molho de tomate fresco para massas e pizzas.','Refogue cebola e alho em azeite. Adicione tomates picados sem pele e sem sementes. Tempere com sal, acucar, manjericao e oregano. Cozinhe em fogo baixo por 30 minutos mexendo ocasionalmente.','Facil',35,NULL,'[]','verdura','Vegano'),(124,'Bruschetta de Tomate','Cafe da Manha','Entrada italiana classica com tomate fresco e manjericao.','Toste fatias de pao no forno ou grelha. Pique tomates maduros e misture com alho, azeite, sal e manjericao. Coloque sobre o pao tostado e sirva imediatamente.','Facil',15,NULL,'[\"Gluten\"]','verdura','Vegano'),(125,'Sopa de Tomate','Jantar','Sopa cremosa de tomate estilo bistro.','Asse tomates cortados ao meio com azeite e alho a 200C por 30 minutos. Bata no liquidificador com caldo de legumes e creme de leite. Volte ao fogo, ajuste o sal e sirva com croutons.','Facil',45,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(126,'Salada Caprese','Acompanhamento','Salada italiana com tomate fresco e mussarela.','Fatie tomates e mussarela em rodelas. Disponha alternando numa travessa. Regue com azeite, tempere com sal e pimenta. Finalize com folhas de manjericao fresco.','Facil',10,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(127,'Bolo de Banana','Sobremesa','Bolo umido e saboroso com bananas maduras.','Amasse 4 bananas maduras. Misture com 2 ovos, 1 xicara de acucar, 1 xicara de oleo e 2 xicaras de farinha com fermento. Asse a 180C por 40 minutos.','Facil',55,NULL,'[\"Gluten\", \"Ovo\"]','outro','Vegetariano'),(128,'Banana Foster','Sobremesa','Sobremesa americana flambeada com banana e sorvete.','Derreta manteiga com acucar mascavo numa frigideira. Adicione bananas cortadas ao meio e cozinhe 2 minutos de cada lado. Adicione rum e flambe. Sirva sobre sorvete de creme.','Media',15,NULL,'[\"Lactose\"]','outro','Vegetariano'),(129,'Smoothie de Banana','Bebida','Smoothie gelado e nutritivo com banana.','Bata no liquidificador 2 bananas congeladas com 200ml de leite, 1 colher de pasta de amendoim e mel a gosto. Sirva gelado imediatamente.','Facil',5,NULL,'[\"Lactose\"]','bebida',NULL),(130,'Torta de Maca','Sobremesa','Torta americana classica com recheio de maca canelada.','Prepare a massa com farinha, manteiga e agua gelada. Forre a forma. Misture macas fatiadas com acucar, canela e farinha. Recheie a torta, cubra com massa e asse a 190C por 50 minutos.','Dificil',90,NULL,'[\"Gluten\", \"Lactose\"]','outro','Vegetariano'),(131,'Salada de Maca com Atum','Almoco','Salada leve e proteica com maca e atum.','Misture atum escorrido com maca picada em cubos, aipo fatiado, maionese, sal e pimenta. Sirva sobre folhas de alface com torradas.','Facil',10,NULL,'[\"Ovo\"]','fruta',NULL),(132,'Suco de Maca com Gengibre','Bebida','Suco refrescante e anti-inflamatorio.','Bata no liquidificador 2 macas sem sementes com 200ml de agua gelada e um pedaco de gengibre fresco. Coe e sirva com gelo.','Facil',5,NULL,'[]','bebida','Vegano'),(133,'Bolo de Laranja','Sobremesa','Bolo fofo e aromatico com calda de laranja.','Bata ovos com acucar e oleo. Adicione suco de laranja e raspas. Misture com farinha e fermento. Asse a 180C por 35 minutos. Cubra com calda de laranja ainda quente.','Facil',50,NULL,'[\"Gluten\", \"Ovo\"]','outro','Vegetariano'),(134,'Frango ao Molho de Laranja','Almoco','Frango suculento com molho agridoce de laranja.','Tempere e sele o frango. Reserve. Prepare molho com suco de laranja, mel, mostarda e alho. Volte o frango ao molho e cozinhe por 20 minutos em fogo baixo. Sirva com arroz.','Media',40,NULL,'[]','carne',NULL),(135,'Vinagrete de Laranja','Acompanhamento','Molho de salada refrescante com laranja.','Misture suco de 1 laranja com azeite, vinagre, mel, sal e pimenta. Bata com garfo ate emulsionar. Use como molho para saladas verdes ou grelhados.','Facil',5,NULL,'[]','fruta','Vegano'),(136,'Guacamole','Acompanhamento','Guacamole mexicano cremoso e temperado.','Amasse 2 abacates maduros. Misture com tomate picado sem sementes, cebola roxa, coentro, suco de limao, sal e pimenta. Sirva imediatamente com chips ou torradas.','Facil',10,NULL,'[]','fruta','Vegano'),(137,'Mousse de Abacate','Sobremesa','Mousse cremoso e saudavel de abacate com limao.','Bata no liquidificador 2 abacates com suco de 2 limoes, leite condensado e uma pitada de sal. Leve a geladeira por 1 hora. Sirva gelado com raspas de limao.','Facil',10,NULL,'[\"Lactose\"]','fruta','Vegano'),(138,'Vitamina de Abacate','Bebida','Vitamina cremosa e nutritiva de abacate.','Bata no liquidificador 1 abacate maduro com 300ml de leite, 2 colheres de acucar e gelo. Sirva gelado imediatamente.','Facil',5,NULL,'[\"Lactose\"]','bebida',NULL),(139,'Limonada Suica','Bebida','Limonada cremosa estilo suico super refrescante.','Bata no liquidificador 4 limoes inteiros sem sementes cortados com 1 litro de agua gelada, acucar e leite condensado. Coe e sirva com gelo.','Facil',10,NULL,'[\"Lactose\"]','bebida',NULL),(140,'Mousse de Limao','Sobremesa','Mousse leve e azedinho de limao com creme de leite.','Misture 1 lata de leite condensado com o suco de 3 limoes. A mistura vai engrossar naturalmente. Incorpore 1 caixa de creme de leite delicadamente. Leve a geladeira por 2 horas e sirva.','Facil',15,NULL,'[\"Lactose\"]','outro','Vegetariano'),(141,'Frango ao Limao','Almoco','Frango grelhado marinado em limao e ervas.','Marine filés de frango em suco de limao, alho, azeite, sal e pimenta por 30 minutos. Grelhe em frigideira quente por 5 minutos de cada lado. Finalize com raspas de limao e salsinha.','Facil',40,NULL,'[]','carne',NULL),(142,'Espinafre Refogado','Acompanhamento','Espinafre refogado com alho e azeite.','Aqueça azeite numa frigideira. Refogue alho picado por 1 minuto. Adicione o espinafre lavado e refogue por 3 minutos ate murchar. Tempere com sal e pimenta.','Facil',10,NULL,'[]','verdura','Vegano'),(143,'Quiche de Espinafre','Almoco','Quiche cremosa com espinafre e queijo.','Forre forma com massa podre. Refogue espinafre com alho. Bata 3 ovos com creme de leite e queijo ralado. Misture o espinafre e despeje na forma. Asse a 180C por 35 minutos.','Media',55,NULL,'[\"Gluten\", \"Lactose\", \"Ovo\"]','ovo','Vegetariano'),(144,'Massa com Espinafre e Ricota','Almoco','Massa cremosa com espinafre fresco e ricota.','Cozinhe o macarrao al dente. Refogue espinafre com alho. Misture ricota com o espinafre, sal, pimenta e noz-moscada. Misture ao macarrao com um pouco da agua do cozimento.','Facil',25,NULL,'[\"Gluten\", \"Lactose\"]','verdura','Vegetariano'),(145,'Brocolis Gratinado','Acompanhamento','Brocolis gratinado com molho branco e queijo.','Cozinhe brocolis no vapor por 5 minutos. Coloque numa assadeira, cubra com molho branco e queijo ralado. Asse a 200C por 20 minutos ate gratinar.','Facil',30,NULL,'[\"Lactose\", \"Gluten\"]','laticinio','Vegetariano'),(146,'Sopa Creme de Brocolis','Jantar','Sopa cremosa e nutritiva de brocolis.','Cozinhe brocolis com batata e cebola em agua com sal. Bata tudo no liquidificador com creme de leite. Volte ao fogo e ajuste o tempero. Sirva com queijo ralado por cima.','Facil',30,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(147,'Risoto de Cogumelo','Almoco','Risoto cremoso e aromatico com cogumelos variados.','Refogue cebola em manteiga. Adicione arroz arboreo e vinho branco. Acrescente caldo quente aos poucos mexendo sempre. Adicione cogumelos refogados. Finalize com parmesao e manteiga.','Media',40,NULL,'[\"Lactose\"]','grao','Vegetariano'),(148,'Cogumelos Refogados','Acompanhamento','Cogumelos suculentos refogados com alho e ervas.','Fatie cogumelos. Aqueça azeite numa frigideira grande e refogue o alho. Adicione os cogumelos em fogo alto sem mexer por 3 minutos. Mexa, tempere com sal, pimenta e tomilho.','Facil',15,NULL,'[]','verdura','Vegano'),(149,'Abobrinha Grelhada','Acompanhamento','Abobrinha grelhada com azeite e ervas frescas.','Corte abobrinhas em rodelas. Tempere com azeite, sal, pimenta e oregano. Grelhe numa frigideira ou churrasqueira por 3 minutos de cada lado. Finalize com hortela fresca.','Facil',15,NULL,'[]','verdura','Vegano'),(150,'Nhoque de Abobrinha','Almoco','Nhoque leve de abobrinha com molho de tomate.','Rale abobrinhas e esprema bem para tirar o liquido. Misture com farinha, ovo, queijo ralado e sal ate formar massa. Modele os nhoques e cozinhe em agua fervente ate subirem. Sirva com molho de tomate.','Media',40,NULL,'[\"Gluten\", \"Ovo\", \"Lactose\"]','verdura','Vegetariano'),(151,'Vitamina de Manga','Bebida','Vitamina tropical e cremosa de manga.','Bata no liquidificador 1 manga madura com 200ml de leite e mel a gosto. Adicione gelo e sirva gelado.','Facil',5,NULL,'[\"Lactose\"]','bebida',NULL),(152,'Salada de Manga com Camarao','Almoco','Salada tropical agridoce com manga e camarao.','Misture manga em cubos com camarao cozido, rucula, cebola roxa fatiada e tomate. Prepare molho com azeite, limao, mel e sal. Regue a salada e sirva imediatamente.','Facil',20,NULL,'[]','carne',NULL),(153,'Chutney de Manga','Acompanhamento','Molho agridoce indiano de manga para acompanhar carnes.','Cozinhe manga picada com acucar, vinagre, gengibre, pimenta vermelha e cravo em fogo baixo por 30 minutos ate engrossar. Deixe esfriar e sirva com frango ou carne.','Media',40,NULL,'[]','fruta','Vegano'),(154,'Vitamina de Morango','Bebida','Vitamina gelada e vibrante de morango.','Bata no liquidificador 200g de morangos com 200ml de leite e 2 colheres de acucar. Adicione gelo e sirva gelado.','Facil',5,NULL,'[\"Lactose\"]','bebida',NULL),(155,'Mousse de Morango','Sobremesa','Mousse leve e rosado de morango fresco.','Bata morangos no liquidificador. Misture com leite condensado e creme de leite batido. Leve a geladeira por 2 horas. Decore com morangos frescos antes de servir.','Facil',15,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(156,'Geleia de Morango','Acompanhamento','Geleia caseira de morango para pao e biscoitos.','Cozinhe 500g de morangos picados com 300g de acucar e suco de limao em fogo medio por 30 minutos mexendo sempre. Quando engrossar e soltar do fundo esta pronta. Deixe esfriar antes de guardar.','Facil',40,NULL,'[]','outro','Vegetariano'),(157,'Sopa Creme de Abobora','Jantar','Sopa cremosa e adocicada de abobora com gengibre.','Asse cubos de abobora com azeite a 200C por 25 minutos. Bata no liquidificador com caldo de legumes, gengibre e creme de leite. Aqueça e sirva com sementes de abobora torradas.','Facil',40,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(158,'Risoto de Abobora','Almoco','Risoto cremoso e levemente adocicado de abobora.','Refogue cebola em manteiga. Adicione arroz arboreo. Acrescente caldo quente aos poucos. Na metade do cozimento adicione pure de abobora. Finalize com parmesao, manteiga e noz-moscada.','Media',45,NULL,'[\"Lactose\"]','grao','Vegetariano'),(159,'Feijoada Simples','Almoco','Feijoada tradicional brasileira simplificada.','Cozinhe feijao preto na pressao com costelinha, linguica e bacon. Refogue cebola e alho, adicione ao feijao com louro e pimenta. Cozinhe por mais 20 minutos. Sirva com arroz, couve e laranja.','Media',90,NULL,'[]','grao','Vegano'),(160,'Tutu de Feijao','Almoco','Tutu mineiro cremoso para acompanhar carne.','Bata feijao cozido no liquidificador com um pouco do caldo. Refogue alho e cebola. Adicione o feijao batido e farinha de mandioca aos poucos mexendo sempre ate engrossar. Tempere e finalize com bacon frito.','Media',30,NULL,'[]','grao','Vegano'),(161,'Molho de Iogurte para Salada','Acompanhamento','Molho cremoso e refrescante de iogurte para saladas.','Misture iogurte natural com pepino ralado e espremido, alho picado, azeite, sal, pimenta e hortela. Sirva gelado com saladas ou como molho para carnes grelhadas.','Facil',10,NULL,'[\"Lactose\"]','laticinio',NULL),(162,'Frango Marinado em Iogurte','Almoco','Frango incrivelmente macio marinado em iogurte e especiarias.','Marine frango em iogurte com curry, curcuma, alho, gengibre, sal e pimenta por pelo menos 2 horas. Grelhe ou asse a 200C por 25 minutos. O iogurte deixa a carne muito macia.','Facil',30,NULL,'[\"Lactose\"]','carne',NULL),(163,'Parfait de Iogurte','Cafe da Manha','Parfait em camadas de iogurte, granola e frutas.','Em um copo transparente, faca camadas alternadas de iogurte natural, granola crocante e frutas frescas picadas. Regue com mel e sirva imediatamente.','Facil',5,NULL,'[\"Lactose\", \"Gluten\"]','laticinio','Vegetariano'),(164,'Biscoito de Manteiga','Sobremesa','Biscoito amanteigado e crocante feito em casa.','Misture 200g de manteiga com 100g de acucar ate cremoso. Adicione 1 ovo e 300g de farinha. Modele os biscoitos e asse a 180C por 12 minutos ate dourar levemente.','Facil',30,NULL,'[\"Gluten\", \"Lactose\", \"Ovo\"]','outro','Vegetariano'),(165,'Sopa de Espinafre','Jantar','Sopa verde e nutritiva de espinafre com creme.','Refogue cebola e alho. Adicione espinafre e caldo de legumes. Cozinhe 10 minutos. Bata no liquidificador com creme de leite. Ajuste o sal e sirva com croutons.','Facil',25,NULL,'[\"Lactose\"]','laticinio','Vegetariano'),(166,'Sopa de Cebola','Jantar','Sopa francesa de cebola com croutons e queijo gratinado.','Caramelize 4 cebolas fatiadas em manteiga por 30 minutos em fogo baixo. Adicione vinho branco e caldo de carne. Cozinhe 15 minutos. Sirva em tigelas com pao tostado e queijo gratinado no forno.','Media',55,NULL,'[\"Lactose\", \"Gluten\"]','laticinio','Vegetariano'),(167,'Camarao ao Alho e Oleo','Almoco','Camarao suculento refogado com bastante alho e azeite.','Tempere camaroes com sal e pimenta. Frite alho fatiado em azeite ate dourar. Adicione os camaroes e refogue por 3 minutos de cada lado. Finalize com salsinha e limao.','Facil',20,NULL,'[]','carne',NULL),(168,'Iogurte com Frutas Vermelhas','Cafe da Manha','Iogurte cremoso com frutas vermelhas frescas e mel.','Coloque iogurte natural em uma tigela. Adicione morangos, amoras e framboesas frescas. Regue com mel e sirva imediatamente.','Facil',5,NULL,'[\"Lactose\"]','laticinio','Sem Gluten'),(169,'Queijo com Geleia','Cafe da Manha','Combinacao classica de queijo fresco com geleia de frutas.','Fatie o queijo fresco em pedacos generosos. Sirva com geleia de morango ou goiabada. Acompanhe com frutas frescas.','Facil',5,NULL,'[\"Lactose\"]','laticinio','Sem Gluten'),(170,'Pudim de Chia com Leite','Sobremesa','Pudim saudavel de chia com leite e frutas.','Misture 3 colheres de chia com 300ml de leite e 1 colher de mel. Deixe na geladeira por 4 horas ou de um dia para o outro. Sirva com frutas frescas por cima.','Facil',10,NULL,'[\"Lactose\"]','laticinio','Sem Gluten'),(171,'Frango ao Creme de Leite','Almoco','Frango cremoso e suculento ao creme de leite.','Tempere e sele filés de frango. Reserve. Refogue alho e cebola. Adicione creme de leite, sal, pimenta e ervas. Volte o frango e cozinhe por 10 minutos. Sirva com arroz.','Facil',30,NULL,'[\"Lactose\"]','laticinio','Sem Gluten'),(172,'Omelete Recheado','Almoco','Omelete generoso recheado com queijo e legumes.','Bata 3 ovos com sal e pimenta. Despeje na frigideira untada. Recheie com queijo, espinafre refogado e tomate. Dobre e sirva quente.','Facil',15,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(173,'Cream Cheese com Salmao','Cafe da Manha','Combinacao rica e proteica de cream cheese com salmao defumado.','Espalhe cream cheese sobre fatias de pepino ou abobrinha. Coloque salmao defumado por cima. Tempere com pimenta, alcaparras e dill. Sirva imediatamente.','Facil',10,NULL,'[\"Lactose\"]','laticinio','Low Carb'),(174,'Iogurte com Nozes e Mel','Cafe da Manha','Iogurte proteico com nozes crocantes e um fio de mel.','Coloque iogurte grego natural numa tigela. Adicione nozes picadas, amendoas e castanhas. Finalize com um fio generoso de mel.','Facil',5,NULL,'[\"Lactose\"]','laticinio','Low Carb'),(175,'Iogurte Natural com Canela','Cafe da Manha','Iogurte natural sem acucar com canela e stevia.','Coloque iogurte natural sem acucar numa tigela. Polvilhe canela em po. Adoce com stevia se desejar. Adicione sementes de chia para mais fibras.','Facil',5,NULL,'[\"Lactose\"]','laticinio','Sem Acucar'),(176,'Mousse de Ricota','Sobremesa','Mousse leve de ricota sem acucar com frutas vermelhas.','Bata ricota com cream cheese e stevia ate ficar cremoso. Adicione raspas de limao. Leve a geladeira por 30 minutos. Sirva com frutas vermelhas frescas.','Facil',15,NULL,'[\"Lactose\"]','laticinio','Sem Acucar'),(177,'Fattoush com Queijo Feta','Almoco','Salada mediterranea refrescante com queijo feta.','Misture tomate, pepino, cebola roxa e hortelã picados. Adicione queijo feta esfarelado. Tempere com azeite, limão, sal e sumac. Misture e sirva.','Facil',15,NULL,'[\"Lactose\"]','laticinio','Dieta Mediterranea'),(178,'Espaguete ao Pesto com Parmesao','Almoco','Massa ao molho pesto fresco com parmesao generoso.','Bata no processador manjericao fresco, pinhoes, alho, azeite e sal ate virar pesto. Cozinhe o espaguete al dente. Misture com o pesto e finalize com parmesao ralado.','Facil',25,NULL,'[\"Gluten\", \"Lactose\"]','laticinio','Dieta Mediterranea'),(179,'Salada de Frutas com Hortelã','Sobremesa','Salada de frutas frescas com hortelã e suco de limao.','Corte em cubos manga, morango, kiwi e maca. Misture com hortelã picada e suco de limao. Leve a geladeira por 15 minutos. Sirva gelada.','Facil',15,NULL,'[]','fruta','Vegetariano'),(180,'Torta de Banana com Aveia','Sobremesa','Torta saudavel de banana com base de aveia.','Misture aveia com manteiga e mel. Forre uma forma. Amasse bananas com canela e lemao. Recheie a torta. Asse a 180C por 25 minutos.','Facil',40,NULL,'[\"Lactose\", \"Gluten\"]','fruta','Vegetariano'),(181,'Suco Verde Detox','Bebida','Suco verde nutritivo com fruta e verdura.','Bata no liquidificador 1 maca, 1 talo de aipo, folhas de espinafre, pepino e suco de limao com agua gelada. Coe e sirva com gelo.','Facil',5,NULL,'[]','fruta','Vegetariano'),(182,'Nicecream de Banana','Sobremesa','Sorvete vegano cremoso feito so de banana congelada.','Congele bananas maduras fatiadas por pelo menos 4 horas. Bata no processador ate virar creme. Adicione cacau em po ou frutas vermelhas se desejar. Sirva imediatamente ou congele mais 30 minutos.','Facil',10,NULL,'[]','fruta','Vegano'),(183,'Chia Pudding de Manga','Cafe da Manha','Pudding de chia com leite vegetal e manga fresca.','Misture 3 colheres de chia com 300ml de leite de coco. Deixe na geladeira por 4 horas. Bata manga com um pouco de agua. Sirva o pudding coberto com o pure de manga.','Facil',10,NULL,'[]','fruta','Vegano'),(184,'Compota de Morango','Acompanhamento','Compota simples de morango para acompanhar diversas sobremesas.','Cozinhe morangos picados com acucar de coco e suco de limao por 15 minutos em fogo medio. Mexa ocasionalmente. Deixe esfriar e sirva com iogurte ou sorvete.','Facil',20,NULL,'[]','fruta','Vegano'),(185,'Pavlova de Frutas Vermelhas','Sobremesa','Merengue crocante coberto com chantilly e frutas vermelhas.','Bata claras em neve com acucar ate picos firmes. Modele num disco e asse a 120C por 1 hora. Cubra com chantilly e frutas vermelhas frescas.','Dificil',80,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(186,'Mousse de Maracuja','Sobremesa','Mousse leve e azedinho de maracuja sem gluten.','Misture suco de maracuja com leite condensado. Incorpore creme de leite batido. Leve a geladeira por 2 horas. Decore com sementes de maracuja.','Facil',15,NULL,'[\"Lactose\"]','fruta','Sem Gluten'),(187,'Creme de Abacate com Tomate','Almoco','Sopa fria cremosa de abacate com tomate fresco.','Bata no liquidificador 2 abacates com tomate, pepino, suco de limao, alho, sal e pimenta. Ajuste a consistencia com agua gelada. Sirva frio decorado com cubinhos de tomate.','Facil',10,NULL,'[]','verdura','Vegano'),(188,'Wok de Legumes','Almoco','Refogado rapido de legumes coloridos no wok.','Aqueça oleo de gergelim no wok. Adicione brocolis, pimentao, cenoura e cogumelo. Refogue em fogo alto por 5 minutos. Tempere com shoyu, gengibre e alho. Sirva com arroz.','Facil',20,NULL,'[]','verdura','Vegano'),(189,'Sopa Minestrone','Jantar','Sopa italiana vegetariana com muitos legumes e macarrao.','Refogue cebola, cenoura e aipo. Adicione tomate, abobrinha, feijao cozido e caldo de legumes. Cozinhe 20 minutos. Adicione macarrao pequeno e cozinhe mais 10 minutos. Finalize com azeite e parmesao.','Facil',45,NULL,'[\"Gluten\"]','verdura','Vegano'),(190,'Lasanha de Legumes','Almoco','Lasanha vegetariana recheada com legumes e molho bechamel.','Refogue abobrinha, berinjela e espinafre. Monte camadas de massa, legumes, molho de tomate e bechamel. Finalize com queijo ralado. Asse a 180C por 40 minutos.','Media',70,NULL,'[\"Gluten\", \"Lactose\"]','verdura','Vegetariano'),(191,'Ovo com Espinafre','Cafe da Manha','Ovos mexidos com espinafre fresco e queijo.','Refogue espinafre com alho. Reserve. Bata ovos com sal. Despeje na frigideira, adicione o espinafre e queijo. Mexa ate cremoso. Sirva com torrada.','Facil',15,NULL,'[\"Ovo\", \"Lactose\"]','verdura','Vegetariano'),(192,'Frittata de Legumes','Almoco','Fritada italiana assada com legumes e ervas.','Refogue cebola, pimentao e abobrinha. Bata 6 ovos com queijo, sal e ervas. Misture com os legumes. Despeje numa frigideira de ferro e asse a 180C por 20 minutos.','Media',35,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(193,'Zoodles ao Pesto','Almoco','Espaguete de abobrinha ao molho pesto fresco.','Espiralze abobrinhas para fazer zoodles. Prepare pesto com manjericao, pinhoes, alho e azeite. Misture os zoodles crus com o pesto. Finalize com parmesao e pimenta.','Facil',15,NULL,'[\"Lactose\"]','verdura','Low Carb'),(194,'Salada Caesar com Frango','Almoco','Salada caesar classica com frango grelhado.','Grelhe frango temperado. Prepare molho caesar com maionese, mostarda, alho, limao e parmesao. Misture alface romana com o molho. Coloque o frango fatiado por cima e finalize com parmesao.','Facil',25,NULL,'[\"Ovo\", \"Lactose\"]','verdura','Low Carb'),(195,'Frango Assado com Ervas','Almoco','Frango assado suculento temperado com ervas frescas.','Tempere o frango com azeite, alho, alecrim, tomilho, sal e pimenta. Marine por 30 minutos. Asse a 200C por 45 minutos regando com o proprio suco.','Facil',60,NULL,'[]','carne','Sem Gluten'),(196,'Peixe ao Molho de Ervas','Almoco','File de peixe assado com molho de ervas frescas.','Tempere files de peixe com sal, limao e pimenta. Grelhe com azeite por 4 minutos de cada lado. Prepare molho com salsinha, cebolinha, alcaparras, limao e azeite. Sirva o peixe coberto com o molho.','Facil',20,NULL,'[]','carne','Sem Gluten'),(197,'Bife Acebolado','Almoco','Bife suculento com cebolas caramelizadas.','Tempere bifes com sal e pimenta. Grelhe em frigideira bem quente por 3 minutos de cada lado. Reserve. Caramelize cebolas fatiadas na mesma frigideira. Sirva o bife coberto com as cebolas.','Facil',20,NULL,'[]','carne','Sem Gluten'),(198,'Frango com Brocolis','Almoco','Frango grelhado com brocolis no alho e azeite.','Grelhe filés de frango temperados. Reserve. Refogue brocolis com alho e azeite por 5 minutos. Sirva o frango com o brocolis ao lado.','Facil',25,NULL,'[]','carne','Low Carb'),(199,'Atum com Salada Verde','Almoco','Atum grelhado sobre cama de folhas verdes.','Tempere atum fresco com sal, pimenta e limao. Grelhe por 2 minutos de cada lado. Prepare salada com rúcula, espinafre e tomate cherry. Sirva o atum sobre a salada com molho de limao e azeite.','Facil',15,NULL,'[]','carne','Low Carb'),(200,'Arroz com Feijao','Almoco','A combinacao classica brasileira simples e nutritiva.','Prepare arroz branco e feijao separados. Refogue cebola e alho, adicione feijao com caldo e tempere. Sirva o arroz com o feijao por cima e salada verde.','Facil',40,NULL,'[]','grao','Vegano'),(201,'Tabule','Acompanhamento','Salada libanesa de trigo com ervas frescas.','Hidrate trigo para quibe com agua morna por 20 minutos. Escorra bem. Misture com tomate picado, pepino, salsinha, hortela, azeite, limao e sal.','Facil',30,NULL,'[\"Gluten\"]','grao','Vegano'),(202,'Macarrao Integral com Azeite','Almoco','Macarrao integral simples e saudavel com azeite e ervas.','Cozinhe macarrao integral al dente. Escorra. Misture com azeite generoso, alho picado, salsinha, pimenta e sal. Sirva imediatamente.','Facil',20,NULL,'[\"Gluten\"]','grao','Vegano'),(203,'Arroz de Legumes','Almoco','Arroz colorido refogado com legumes frescos.','Refogue cebola, pimentao e cenoura. Adicione arroz lavado e frite por 2 minutos. Acrescente agua quente com sal. Cozinhe em fogo baixo por 15 minutos. Finalize com ervilha e cheiro-verde.','Facil',25,NULL,'[]','grao','Vegetariano'),(204,'Macarrao ao Pesto Vermelho','Almoco','Macarrao com pesto de tomate seco e parmesao.','Bata tomates secos com pinhoes, alho, azeite e parmesao. Cozinhe o macarrao al dente. Misture com o pesto vermelho e sirva com mais parmesao.','Facil',25,NULL,'[\"Gluten\", \"Lactose\"]','grao','Vegetariano'),(205,'Arroz com Coco','Acompanhamento','Arroz aromatico cozido no leite de coco.','Refogue arroz no azeite. Adicione leite de coco misturado com agua na proporcao 1:1. Tempere com sal. Cozinhe em fogo baixo por 15 minutos. Sirva com frango ou peixe.','Facil',25,NULL,'[]','grao','Sem Gluten'),(206,'Polenta Cremosa','Acompanhamento','Polenta cremosa e aveludada para acompanhar carnes.','Ferva agua com sal. Adicione fubá aos poucos mexendo sempre. Cozinhe por 20 minutos em fogo baixo. Finalize com manteiga e queijo parmesao ralado.','Facil',30,NULL,'[\"Lactose\"]','grao','Sem Gluten'),(207,'Agua de Coco com Hortelã','Bebida','Bebida refrescante e hidratante com agua de coco e hortelã.','Misture agua de coco gelada com folhas de hortelã amassadas e suco de limao. Adicione gelo e sirva imediatamente.','Facil',5,NULL,'[]','bebida','Vegano'),(208,'Kombucha de Gengibre','Bebida','Bebida fermentada probiotica com toque de gengibre.','Prepare cha preto adocado e deixe esfriar. Adicione SCOBY e deixe fermentar por 7 dias em temperatura ambiente. Adicione gengibre ralado na segunda fermentacao por 2 dias. Sirva gelado.','Dificil',10,NULL,'[]','bebida','Vegano'),(209,'Suco de Beterraba com Maca','Bebida','Suco energizante e antioxidante de beterraba com maca.','Passe pela centrífuga ou bata no liquidificador 1 beterraba crua, 1 maca e 1 cenoura com agua gelada. Coe e sirva com gelo e suco de limao.','Facil',10,NULL,'[]','bebida','Vegano'),(210,'Golden Milk','Bebida','Leite dourado anti-inflamatorio com curcuma e especiarias.','Aqueça leite com curcuma, canela, gengibre, pimenta preta e mel. Mexa bem ate dissolver. Sirva quente ou gelado. Pode substituir o leite por bebida vegetal.','Facil',10,NULL,'[\"Lactose\"]','bebida','Vegetariano'),(211,'Vitamina de Abacaxi com Hortelã','Bebida','Vitamina tropical refrescante e digestiva.','Bata no liquidificador fatias de abacaxi com leite de coco, hortelã fresca e gelo. Adoce com mel se necessario. Sirva gelado imediatamente.','Facil',5,NULL,'[]','bebida','Vegetariano'),(212,'Tapioca Recheada','Cafe da Manha','Tapioca crocante com recheios variados.','Umedeca a tapioca granulada e espalhe numa frigideira quente seca. Deixe formar uma panqueca crocante. Recheie com queijo e banana ou coco com mel. Dobre e sirva quente.','Facil',10,NULL,'[\"Lactose\"]','outro','Vegetariano'),(213,'Crepioca','Cafe da Manha','Crepe de tapioca com ovo nutritivo e saboroso.','Misture 1 ovo com 2 colheres de tapioca granulada. Despeje numa frigideira antiaderente e espalhe. Cozinhe por 2 minutos de cada lado. Recheie com queijo ou banana.','Facil',10,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(214,'Bowl de Acai','Cafe da Manha','Bowl energetico de acai com granola e frutas.','Bata acai congelado com leite ou suco de guarana ate ficar cremoso. Coloque numa tigela. Decore com granola, banana fatiada, morango e mel.','Facil',10,NULL,'[\"Lactose\", \"Gluten\"]','outro','Sem Gluten'),(215,'Brigadeiro de Colher Sem Gluten','Sobremesa','Brigadeiro cremoso sem gluten para qualquer ocasiao.','Misture leite condensado com cacau em po e manteiga. Cozinhe em fogo medio mexendo sempre ate soltar do fundo. Sirva de colher em copinhos decorados com granulado.','Facil',15,NULL,'[\"Lactose\"]','outro','Sem Gluten'),(216,'Shakshuka','Almoco','Ovos pochados em molho de tomate temperado estilo mediterraneo.','Refogue cebola, alho e pimentao em azeite. Adicione tomates pelados, cominho, paprica e pimenta. Cozinhe 10 minutos. Abra cavidades no molho e quebre os ovos dentro. Tampe e cozinhe em fogo baixo por 8 minutos. Sirva com pao.','Facil',25,NULL,'[\"Ovo\", \"Gluten\"]','ovo','Vegetariano'),(217,'Ovo Estrelado Perfeito','Cafe da Manha','Ovo frito com bordas crocantes e gema mole.','Aqueça frigideira em fogo medio-alto com manteiga. Quebre o ovo com cuidado. Regue a gema com a manteiga quente usando uma colher. Cozinhe por 2 minutos para gema mole ou 3 para gema dura. Tempere com sal e pimenta.','Facil',5,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(218,'Ovos Benedict','Cafe da Manha','Classico cafe da manha americano com ovo pochado e molho holandes.','Prepare molho holandes batendo gemas com manteiga clarificada e limao em banho-maria. Toste metades de english muffin. Coloque presunto e ovo pochado por cima. Cubra com o molho holandes e decore com paprica.','Dificil',40,NULL,'[\"Ovo\", \"Gluten\", \"Lactose\"]','ovo',NULL),(219,'Creme de Ovo','Sobremesa','Creme aveludado de ovo para rechear bolos e tortas.','Bata gemas com acucar ate esbranquicar. Adicione amido de milho e misture. Aqueça leite ate quase ferver e despeje sobre as gemas mexendo sempre. Volte ao fogo baixo mexendo ate engrossar. Finalize com manteiga e baunilha.','Media',20,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(220,'Ovo Mexido Cremoso','Cafe da Manha','Ovo mexido super cremoso feito em fogo baixo.','Bata ovos com sal. Despeje na frigideira fria com manteiga. Ligue o fogo baixo e mexa lentamente com espatula dobrando os ovos. Retire do fogo antes de firmar completamente. Finalize com cebolinha e pimenta.','Facil',8,NULL,'[\"Ovo\", \"Lactose\"]','ovo','Vegetariano'),(221,'Tortilha Espanhola','Almoco','Omelete espanhola com batata e cebola caramelizada.','Frite batatas fatiadas em azeite ate macias. Reserve. Caramelize cebola fatiada. Bata 6 ovos e misture com batata e cebola. Despeje na frigideira e cozinhe em fogo baixo por 8 minutos. Vire com um prato e cozinhe mais 5 minutos.','Media',35,NULL,'[\"Ovo\"]','ovo','Vegetariano'),(222,'Soufle de Queijo','Almoco','Soufle classico frances leve e aerado.','Prepare bechamel e misture com queijo ralado. Incorpore gemas. Bata claras em neve firme e incorpore delicadamente. Despeje em ramequins untados. Asse a 190C por 15 minutos sem abrir o forno. Sirva imediatamente.','Dificil',45,NULL,'[\"Ovo\", \"Lactose\", \"Gluten\"]','ovo','Vegetariano'),(223,'Macarrao com Atum','Almoco','Macarrao rapido e saboroso com atum em lata.','Cozinhe o macarrao al dente. Refogue alho em azeite. Adicione atum escorrido e desmanchado, azeitonas e tomate cereja cortado. Misture ao macarrao com um pouco da agua do cozimento. Finalize com salsinha e limao.','Facil',20,NULL,'[\"Gluten\"]','enlatado',NULL),(224,'Salada de Atum','Almoco','Salada proteica e rapida com atum em lata.','Escorra o atum e desmanche com um garfo. Misture com cebola roxa picada, tomate, maionese, sal, pimenta e suco de limao. Sirva sobre alface ou com torradas.','Facil',10,NULL,'[\"Ovo\"]','enlatado','Low Carb'),(225,'Patê de Atum','Cafe da Manha','Pate cremoso de atum para passar no pao.','Bata no processador atum escorrido com cream cheese, suco de limao, alcaparras e pimenta. Ajuste o sal. Leve a geladeira por 30 minutos. Sirva com torradas ou crackers.','Facil',10,NULL,'[\"Lactose\"]','enlatado','Low Carb'),(226,'Arroz com Atum e Milho','Almoco','Arroz temperado com atum e milho verde.','Cozinhe arroz normalmente. Refogue cebola e alho. Adicione atum escorrido, milho verde, ervilha e temperos. Misture com o arroz e finalize com cheiro-verde. Sirva quente.','Facil',25,NULL,'[]','enlatado',NULL),(227,'Sopa de Tomate com Grao de Bico','Jantar','Sopa encorpada com tomate pelado e grao de bico em lata.','Refogue cebola e alho em azeite. Adicione tomate pelado em lata amassado e caldo de legumes. Cozinhe 15 minutos. Adicione grao de bico escorrido e temperos. Finalize com azeite e manjericao fresco.','Facil',30,NULL,'[]','enlatado','Vegano'),(228,'Sardinha Grelhada com Limaoo','Almoco','Sardinha em lata grelhada com temperos frescos.','Escorra as sardinhas em lata. Grelhe numa frigideira com azeite por 2 minutos de cada lado. Tempere com limao, pimenta e salsinha. Sirva com arroz ou salada verde.','Facil',10,NULL,'[]','enlatado',NULL),(229,'Pataniscas de Bacalhau','Almoco','Bolinhos fritos de bacalhau em lata com ervas.','Misture bacalhau em lata escorrido com ovo, cebola picada, salsinha, farinha e pimenta ate formar massa. Frite colheradas em oleo quente ate dourar. Escorra e sirva com arroz de feijao.','Media',30,NULL,'[\"Ovo\", \"Gluten\"]','enlatado',NULL),(230,'Feijao Tropeiro','Almoco','Feijao tropeiro mineiro com bacon e farofa.','Frite bacon picado ate crocante. Adicione cebola e alho. Junte feijao em lata escorrido e misture bem. Adicione farinha de mandioca aos poucos mexendo sempre ate ficar soltinho. Tempere com sal e finalize com salsinha e ovo cozido picado.','Media',25,NULL,'[\"Ovo\"]','enlatado',NULL),(231,'Wrap de Atum','Almoco','Wrap leve e proteico com atum e salada.','Misture atum escorrido com maionese, milho e cebola. Coloque sobre uma tortilha com alface, tomate e pepino. Enrole firmemente e corte ao meio. Sirva imediatamente.','Facil',10,NULL,'[\"Ovo\", \"Gluten\"]','enlatado',NULL),(232,'Sopa de Feijao com Linguica','Jantar','Sopa cremosa de feijao com linguica defumada.','Refogue linguica fatiada ate dourar. Adicione cebola, alho e tomate. Junte feijao em lata com um pouco do caldo e agua. Cozinhe 15 minutos. Amasse parte do feijao para engrossar. Tempere e finalize com cheiro-verde.','Facil',25,NULL,'[]','enlatado',NULL),(233,'Pizza de Sardinha','Jantar','Pizza rapida com sardinha em lata e azeitona.','Abra a massa de pizza. Espalhe molho de tomate. Distribua sardinhas em lata escorridas, cebola em rodelas e azeitonas. Cubra com queijo mussarela. Asse a 220C por 15 minutos ate a borda dourar.','Facil',25,NULL,'[\"Gluten\", \"Lactose\"]','enlatado',NULL);
